ee:message.ee:set-payload:
%dw 2.0
import fromBase64 from dw::core::Binaries
import seconds from dw::core::Periods
output application/json
var jwtToken = vars.login."JDE Token"
var jwtPayload =
    (jwtToken splitBy ".")[1]
        then fromBase64($) as String
        then read($, "application/json")
var expSeconds = jwtPayload.exp default null
var expDateTime =
    if (expSeconds != null)
        |1970-01-01T00:00:00Z| + seconds(expSeconds as Number)
    else
        null
---
{
	environment: jwtPayload.user,
	role: jwtPayload.role,
	user: jwtPayload.user 
} ++
(
    if (expDateTime != null)
        {
            expiresAt: expDateTime
        }
    else
        {}
)

jdeatina:invoke-ws.jdeatina:input-parameters:
#[output application/java
---
{
	"JDE Token": vars.autenticate."JDE Token",
	header: {
		businessUnit: p('po.businessUnitCode'),
		purchaseOrderKey: {
			documentTypeCode: vars.parameters.documentOrderTypeCode,
			documentNumber: vars.parameters.documentOrderInvoiceNumber,
			documentCompany: vars.parameters.documentCompanyKeyOrderNo
		}
	}
}]

ee:variables.ee:set-variable:
%dw 2.0
output application/java

var inputObject = vars.order.showPurchaseOrder[0] default {}

---
{
    statusApproval: p("po.statusApproval"),
    approvalRoutingCodePurchaseOrder: inputObject.header.approvedRoutingBy,
    amountGross: inputObject.header.amountGross default 0,
    businessUnitCode: inputObject.header.businessUnit
}
